package main

import (
	"fmt"
	"html/template"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize user inputs to prevent HTML injection attacks
	safeUserName := template.HTMLEscapeString(userName)
	safeSubject := template.HTMLEscapeString(subject)
	safeFeedbackContent := template.HTMLEscapeString(feedbackContent)

	// Construct email headers - escape header values to prevent header injection
	// Replace any CR or LF characters in header values to prevent header injection attacks
	safeFromAddr := sanitizeHeaderValue(fromAddr)
	safeToAddr := sanitizeHeaderValue(toAddr)
	safeEmailSubject := sanitizeHeaderValue(fmt.Sprintf("Feedback: %s", safeSubject))

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		safeFromAddr,
		safeToAddr,
		safeEmailSubject,
	)

	// Construct HTML body with sanitized inputs
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// sanitizeHeaderValue removes CR and LF characters from header values to prevent
// email header injection attacks. An attacker could inject additional headers
// or modify the email structure by including newline characters in input.
func sanitizeHeaderValue(value string) string {
	// Remove carriage return and line feed characters
	value = strings.ReplaceAll(value, "\r", "")
	value = strings.ReplaceAll(value, "\n", "")
	return value
}

