package main

import (
	"bytes"
	"encoding/base64"
	"fmt"
	"mime/multipart"
	"net/textproto"
)

// BuildFeedbackEmail generates an HTML-formatted email for user feedback submission.
// It uses net/smtp compatible format with proper MIME encoding.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Create a buffer to build the email
	var buf bytes.Buffer

	// Generate boundary for multipart message
	boundary := "----=_Part_Boundary_Feedback_Email"

	// Write email headers
	buf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	buf.WriteString(fmt.Sprintf("Subject: User Feedback: %s\r\n", subject))
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString(fmt.Sprintf("Content-Type: multipart/alternative; boundary=\"%s\"\r\n", boundary))
	buf.WriteString("\r\n")

	// Build HTML content
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            max-width: 600px;
            margin: 0 auto;
            padding: 20px;
        }
        .header {
            background-color: #4CAF50;
            color: white;
            padding: 20px;
            text-align: center;
            border-radius: 5px 5px 0 0;
        }
        .content {
            background-color: #f9f9f9;
            padding: 20px;
            border: 1px solid #ddd;
            border-radius: 0 0 5px 5px;
        }
        .field {
            margin-bottom: 15px;
        }
        .label {
            font-weight: bold;
            color: #555;
            display: block;
            margin-bottom: 5px;
        }
        .value {
            background-color: white;
            padding: 10px;
            border: 1px solid #e0e0e0;
            border-radius: 3px;
        }
        .feedback-box {
            background-color: white;
            padding: 15px;
            border: 1px solid #e0e0e0;
            border-radius: 3px;
            white-space: pre-wrap;
            word-wrap: break-word;
        }
    </style>
</head>
<body>
    <div class="header">
        <h1>User Feedback Received</h1>
    </div>
    <div class="content">
        <div class="field">
            <span class="label">Username:</span>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <span class="label">Subject:</span>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <span class="label">Feedback Content:</span>
            <div class="feedback-box">%s</div>
        </div>
    </div>
</body>
</html>`, escapeHTML(userName), escapeHTML(subject), escapeHTML(feedbackContent))

	// Write plain text part
	buf.WriteString(fmt.Sprintf("--%s\r\n", boundary))
	buf.WriteString("Content-Type: text/plain; charset=UTF-8\r\n")
	buf.WriteString("Content-Transfer-Encoding: quoted-printable\r\n")
	buf.WriteString("\r\n")
	buf.WriteString(fmt.Sprintf("User Feedback\n\n"))
	buf.WriteString(fmt.Sprintf("Username: %s\n", userName))
	buf.WriteString(fmt.Sprintf("Subject: %s\n", subject))
	buf.WriteString(fmt.Sprintf("Feedback Content:\n%s\n", feedbackContent))
	buf.WriteString("\r\n")

	// Write HTML part
	buf.WriteString(fmt.Sprintf("--%s\r\n", boundary))
	buf.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	buf.WriteString("Content-Transfer-Encoding: base64\r\n")
	buf.WriteString("\r\n")

	// Encode HTML content in base64
	encodedHTML := base64.StdEncoding.EncodeToString([]byte(htmlContent))
	// Wrap base64 content at 76 characters per line for SMTP compatibility
	for i := 0; i < len(encodedHTML); i += 76 {
		end := i + 76
		if end > len(encodedHTML) {
			end = len(encodedHTML)
		}
		buf.WriteString(encodedHTML[i:end])
		buf.WriteString("\r\n")
	}

	// Close boundary
	buf.WriteString(fmt.Sprintf("--%s--\r\n", boundary))

	return buf.String(), nil
}

// escapeHTML escapes special HTML characters to prevent XSS
func escapeHTML(s string) string {
	var result bytes.Buffer
	for _, r := range s {
		switch r {
		case '&':
			result.WriteString("&amp;")
		case '<':
			result.WriteString("&lt;")
		case '>':
			result.WriteString("&gt;")
		case '"':
			result.WriteString("&quot;")
		case '\'':
			result.WriteString("&#39;")
		default:
			result.WriteRune(r)
		}
	}
	return result.String()
}

