// BuildFeedbackEmail generates an HTML-formatted email for user feedback.
// It constructs a multipart email with both plain text and HTML versions.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Create a buffer to build the email
	var buf bytes.Buffer

	// Generate boundary for multipart message
	writer := multipart.NewWriter(&buf)
	boundary := writer.Boundary()

	// Build email headers
	headers := fmt.Sprintf("From: %s\r\n", fromAddr)
	headers += fmt.Sprintf("To: %s\r\n", toAddr)
	headers += fmt.Sprintf("Subject: User Feedback: %s\r\n", subject)
	headers += "MIME-Version: 1.0\r\n"
	headers += fmt.Sprintf("Content-Type: multipart/alternative; boundary=%q\r\n", boundary)
	headers += "\r\n"

	// Write headers to buffer
	buf.WriteString(headers)

	// Plain text part
	textPartHeader := make(textproto.MIMEHeader)
	textPartHeader.Set("Content-Type", "text/plain; charset=UTF-8")
	textPartHeader.Set("Content-Transfer-Encoding", "quoted-printable")

	textPart, err := writer.CreatePart(textPartHeader)
	if err != nil {
		return "", fmt.Errorf("failed to create text part: %w", err)
	}

	textContent := fmt.Sprintf(
		"User Feedback Submission\n\n"+
			"Username: %s\n"+
			"Subject: %s\n\n"+
			"Feedback Content:\n%s\n",
		userName, subject, feedbackContent,
	)
	textPart.Write([]byte(textContent))

	// HTML part
	htmlPartHeader := make(textproto.MIMEHeader)
	htmlPartHeader.Set("Content-Type", "text/html; charset=UTF-8")
	htmlPartHeader.Set("Content-Transfer-Encoding", "quoted-printable")

	htmlPart, err := writer.CreatePart(htmlPartHeader)
	if err != nil {
		return "", fmt.Errorf("failed to create html part: %w", err)
	}

	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            max-width: 600px;
            margin: 0 auto;
            padding: 20px;
        }
        .header {
            background-color: #4CAF50;
            color: white;
            padding: 20px;
            text-align: center;
            border-radius: 5px 5px 0 0;
        }
        .content {
            background-color: #f9f9f9;
            padding: 20px;
            border: 1px solid #ddd;
            border-radius: 0 0 5px 5px;
        }
        .field {
            margin-bottom: 15px;
        }
        .label {
            font-weight: bold;
            color: #555;
            display: block;
            margin-bottom: 5px;
        }
        .value {
            background-color: white;
            padding: 10px;
            border: 1px solid #e0e0e0;
            border-radius: 3px;
        }
        .feedback-box {
            background-color: white;
            padding: 15px;
            border: 1px solid #e0e0e0;
            border-radius: 3px;
            min-height: 100px;
            white-space: pre-wrap;
        }
    </style>
</head>
<body>
    <div class="header">
        <h1>User Feedback Submission</h1>
    </div>
    <div class="content">
        <div class="field">
            <span class="label">Username:</span>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <span class="label">Subject:</span>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <span class="label">Feedback Content:</span>
            <div class="feedback-box">%s</div>
        </div>
    </div>
</body>
</html>`,
		escapeHTML(userName),
		escapeHTML(subject),
		escapeHTML(feedbackContent),
	)
	htmlPart.Write([]byte(htmlContent))

	// Close the multipart writer
	err = writer.Close()
	if err != nil {
		return "", fmt.Errorf("failed to close writer: %w", err)
	}

	return buf.String(), nil
}

// escapeHTML escapes special HTML characters to prevent XSS
func escapeHTML(s string) string {
	var result bytes.Buffer
	for _, r := range s {
		switch r {
		case '<':
			result.WriteString("&lt;")
		case '>':
			result.WriteString("&gt;")
		case '&':
			result.WriteString("&amp;")
		case '"':
			result.WriteString("&quot;")
		case '\'':
			result.WriteString("&#39;")
		default:
			result.WriteRune(r)
		}
	}
	return result.String()
}

// encodeBase64 encodes a string to base64 for email content transfer encoding
func encodeBase64(s string) string {
	return base64.StdEncoding.EncodeToString([]byte(s))
}

func main() {
	// Example usage
	emailBody, err := BuildFeedbackEmail(
		"support@example.com",
