</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// htmlEscape escapes special HTML characters to prevent XSS attacks
func htmlEscape(s string) string {
	result := ""
	for _, r := range s {
		switch r {
		case '<':
			result += "&lt;"
		case '>':
			result += "&gt;"
		case '&':
			result += "&amp;"
		case '"':
			result += "&quot;"
		case '\'':
			result += "&#39;"
		default:
			result += string(r)
		}
	}
	return result
}

