// htmlEscape escapes special HTML characters
func htmlEscape(s string) string {
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, "\"", "&quot;")
	s = strings.ReplaceAll(s, "'", "&#39;")
	return s
}

// escapeHeader escapes special characters in email header fields
func escapeHeader(s string) string {
	// Replace newline characters to prevent header injection
	s = strings.ReplaceAll(s, "\r", " ")
	s = strings.ReplaceAll(s, "\n", " ")
	return s
}

// encodeQuotedPrintable encodes text using quoted-printable encoding
func encodeQuotedPrintable(s string) string {
	var result strings.Builder
	lineLength := 0

	for i := 0; i < len(s); i++ {
		c := s[i]

		// Characters that can be represented as-is
		if (c >= 33 && c <= 60) || (c >= 62 && c <= 126) {
			// Check if we need to wrap the line
			if lineLength >= 75 {
				result.WriteString("=\r\n")
				lineLength = 0
			}
			result.WriteByte(c)
			lineLength++
		} else if c == ' ' || c == '\t' {
			// Space or tab at end of line needs encoding
			if i+1 < len(s) && (s[i+1] == '\r' || s[i+1] == '\n') {
				result.WriteString(fmt.Sprintf("=%02X", c))
				lineLength += 3
			} else {
				if lineLength >= 75 {
					result.WriteString("=\r\n")
					lineLength = 0
				}
				result.WriteByte(c)
				lineLength++
			}
		} else if c == '\r' || c == '\n' {
			// Line break - reset counter
			result.WriteByte(c)
			if c == '\r' && i+1 < len(s) && s[i+1] == '\n' {
				result.WriteByte(s[i+1])
				i++
			}
			lineLength = 0
		} else {
			// Encode other characters
			encoded := fmt.Sprintf("=%02X", c)
			if lineLength+len(encoded) > 75 {
				result.WriteString("=\r\n")
				lineLength = 0
			}
			result.WriteString(encoded)
			lineLength += len(encoded)
		}
	}

	return result.String()
}

