	safeFromAddr := strings.ReplaceAll(strings.ReplaceAll(fromAddr, "\r\n", ""), "\n", "")
	safeToAddr := strings.ReplaceAll(strings.ReplaceAll(toAddr, "\r\n", ""), "\n", "")

