// BuildFeedbackEmail generates an HTML-formatted email for user feedback.
// It constructs a multipart email with both plain text and HTML versions.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Create a buffer to build the email
	var buf bytes.Buffer

	// Generate boundary for multipart message
	writer := multipart.NewWriter(&buf)
	boundary := writer.Boundary()

	// Build email headers
	headers := fmt.Sprintf("From: %s\r\n", fromAddr)
	headers += fmt.Sprintf("To: %s\r\n", toAddr)
	headers += fmt.Sprintf("Subject: User Feedback: %s\r\n", subject)
	headers += "MIME-Version: 1.0\r\n"
	headers += fmt.Sprintf("Content-Type: multipart/alternative; boundary=%q\r\n", boundary)
	headers += "\r\n"

