// encodeRFC2047 encodes a string using RFC 2047 encoding for email subjects
func encodeRFC2047(s string) string {
	// Use base64 encoding for UTF-8 strings
	encoded := base64.StdEncoding.EncodeToString([]byte(s))
	return "=?UTF-8?B?" + encoded + "?="
}

// encodeQuotedPrintable encodes text using quoted-printable encoding
func encodeQuotedPrintable(s string) string {
	var buf bytes.Buffer
	lineLen := 0

	for i := 0; i < len(s); i++ {
		c := s[i]

		// Check if we need to wrap the line (max 76 chars per line in QP)
		if lineLen >= 73 {
			buf.WriteString("=\r\n")
			lineLen = 0
		}

		// Characters that can be represented as-is
		if c >= 33 && c <= 126 && c != '=' && c != '?' && c != '_' {
			buf.WriteByte(c)
			lineLen++
		} else if c == ' ' || c == '\t' {
			// Space or tab at end of line needs encoding
			if i+1 < len(s) && (s[i+1] == '\r' || s[i+1] == '\n') {
				buf.WriteString(fmt.Sprintf("=%02X", c))
				lineLen += 3
			} else {
				buf.WriteByte(c)
				lineLen++
			}
		} else if c == '\r' || c == '\n' {
			// Line breaks are preserved
			buf.WriteByte(c)
			if c == '\r' && i+1 < len(s) && s[i+1] == '\n' {
				buf.WriteByte(s[i+1])
				i++
			}
			lineLen = 0
		} else {
			// Encode other characters
			buf.WriteString(fmt.Sprintf("=%02X", c))
			lineLen += 3
		}
	}

	return buf.String()
}

