// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize inputs to prevent header injection attacks
	// Remove any CRLF characters that could be used to inject additional headers
	safeFromAddr := sanitizeHeaderField(fromAddr)
	safeToAddr := sanitizeHeaderField(toAddr)
	safeSubject := sanitizeHeaderField(subject)

	// For display in HTML body, use HTML escaping to prevent XSS
	safeUserNameHTML := template.HTMLEscapeString(userName)
	safeSubjectHTML := template.HTMLEscapeString(subject)
	safeFeedbackContentHTML := template.HTMLEscapeString(feedbackContent)

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	// Use quoted-printable or base64 if subject has non-ASCII, but assume ASCII for simplicity
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		safeFromAddr,
		safeToAddr,
		emailSubject,
	)

	// Construct HTML body with properly escaped content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserNameHTML,
		safeSubjectHTML,
		safeFeedbackContentHTML,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// sanitizeHeaderField removes CR and LF characters to prevent email header injection attacks.
// Header injection can occur when untrusted input containing newlines is placed into email headers,
// allowing attackers to inject additional headers or modify the email structure.
func sanitizeHeaderField(input string) string {
	// Replace both \r and \n with empty string to prevent header injection
	// Also replace null bytes which can cause issues in some systems
	input = strings.ReplaceAll(input, "\r", "")
	input = strings.ReplaceAll(input, "\n", "")
	input = strings.ReplaceAll(input, "\x00", "")
	return input
}

