func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate required parameters
	if fromAddr == "" {
		return "", fmt.Errorf("from address cannot be empty")
	}
	if toAddr == "" {
		return "", fmt.Errorf("to address cannot be empty")
	}
	if userName == "" {
		return "", fmt.Errorf("user name cannot be empty")
	}
	if subject == "" {
		return "", fmt.Errorf("subject cannot be empty")
	}
	if feedbackContent == "" {
		return "", fmt.Errorf("feedback content cannot be empty")
	}

	// Create a buffer to build the email
	var buf bytes.Buffer

	// Generate a unique boundary for multipart message
	boundary := "----=_Part_Feedback_Email_Boundary"

	// Write email headers
	buf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	buf.WriteString(fmt.Sprintf("Subject: [User Feedback] %s\r\n", subject))
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString(fmt.Sprintf("Content-Type: multipart/alternative; boundary=\"%s\"\r\n", boundary))
	buf.WriteString("\r\n")

	// Create multipart writer
	mw := multipart.NewWriter(&buf)
	mw.SetBoundary(boundary)

	// Plain text part
	textHeaders := make(textproto.MIMEHeader)
	textHeaders.Set("Content-Type", "text/plain; charset=UTF-8")
	textHeaders.Set("Content-Transfer-Encoding", "quoted-printable")

	textPart, err := mw.CreatePart(textHeaders)
	if err != nil {
		return "", fmt.Errorf("failed to create text part: %w", err)
	}

	textContent := fmt.Sprintf("User Feedback Submission\n\n"+
		"Username: %s\n"+
		"Subject: %s\n"+
		"Feedback Content:\n%s\n",
