	_, err = textPart.Write([]byte(textContent))
	if err != nil {
		return "", fmt.Errorf("failed to write text content: %w", err)
	}

	// HTML part
	htmlHeaders := make(textproto.MIMEHeader)
	htmlHeaders.Set("Content-Type", "text/html; charset=UTF-8")
	htmlHeaders.Set("Content-Transfer-Encoding", "base64")

	htmlPart, err := mw.CreatePart(htmlHeaders)
	if err != nil {
		return "", fmt.Errorf("failed to create HTML part: %w", err)
