        .field {
            margin-bottom: 15px;
        }
        .label {
            font-weight: bold;
            color: #555;
            display: block;
            margin-bottom: 5px;
        }
        .value {
            background-color: white;
            padding: 10px;
            border: 1px solid #eee;
            border-radius: 3px;
        }
        .feedback-box {
            background-color: white;
            padding: 15px;
            border: 1px solid #ddd;
            border-radius: 3px;
            white-space: pre-wrap;
        }
    </style>
</head>
<body>
    <div class="header">
        <h1>📧 User Feedback Submission</h1>
    </div>
    <div class="content">
        <div class="field">
            <span class="label">👤 Username:</span>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <span class="label">📝 Subject:</span>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <span class="label">💬 Feedback Content:</span>
            <div class="feedback-box">%s</div>
        </div>
    </div>
</body>
</html>`, escapeHTML(userName), escapeHTML(subject), escapeHTML(feedbackContent))

