package main

import (
	"bytes"
	"encoding/base64"
	"fmt"
	"mime/multipart"
	"net/textproto"
)

// BuildFeedbackEmail generates an HTML-formatted email for user feedback submission.
// It uses net/smtp compatible format with proper MIME encoding.
//
// Parameters:
//   - fromAddr: sender email address
//   - toAddr: recipient email address (customer support team)
//   - userName: name of the user submitting feedback
//   - subject: feedback subject/title
//   - feedbackContent: detailed feedback content from user
//
// Returns:
//   - emailBody: complete email body ready to be sent via SMTP
//   - err: any error encountered during email construction
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Validate required fields
	if fromAddr == "" {
		return "", fmt.Errorf("from address is required")
	}
	if toAddr == "" {
		return "", fmt.Errorf("to address is required")
	}
	if userName == "" {
		return "", fmt.Errorf("user name is required")
	}

	// Create a buffer to build the email
	var buf bytes.Buffer

	// Create multipart writer for mixed content
	writer := multipart.NewWriter(&buf)

	// Write email headers
	buf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	buf.WriteString(fmt.Sprintf("Subject: [User Feedback] %s\r\n", subject))
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString(fmt.Sprintf("Content-Type: multipart/alternative; boundary=%s\r\n", writer.Boundary()))
	buf.WriteString("\r\n")

	// Create plain text part
	textHeader := make(textproto.MIMEHeader)
	textHeader.Set("Content-Type", "text/plain; charset=\"utf-8\"")
	textHeader.Set("Content-Transfer-Encoding", "quoted-printable")

	textPart, err := writer.CreatePart(textHeader)
	if err != nil {
		return "", fmt.Errorf("failed to create text part: %w", err)
	}

	plainTextContent := fmt.Sprintf(
		"User Feedback Submission\n\n"+
			"Username: %s\n"+
			"Subject: %s\n\n"+
			"Feedback Content:\n%s\n",
		userName,
		subject,
		feedbackContent,
	)
	textPart.Write([]byte(plainTextContent))

	// Create HTML part
	htmlHeader := make(textproto.MIMEHeader)
	htmlHeader.Set("Content-Type", "text/html; charset=\"utf-8\"")
	htmlHeader.Set("Content-Transfer-Encoding", "quoted-printable")

	htmlPart, err := writer.CreatePart(htmlHeader)
	if err != nil {
		return "", fmt.Errorf("failed to create html part: %w", err)
	}

	// Build HTML content with proper escaping and formatting
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>User Feedback</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            max-width: 600px;
            margin: 0 auto;
            padding: 20px;
        }
        .header {
            background-color: #4a90d9;
            color: white;
            padding: 20px;
            border-radius: 5px 5px 0 0;
        }
        .content {
            background-color: #f9f9f9;
            padding: 20px;
            border: 1px solid #ddd;
            border-top: none;
            border-radius: 0 0 5px 5px;
        }
        .field {
            margin-bottom: 15px;
        }
        .label {
            font-weight: bold;
            color: #555;
            display: block;
            margin-bottom: 5px;
        }
        .value {
            background-color: white;
            padding: 10px;
            border: 1px solid #e0e0e0;
            border-radius: 3px;
        }
        .feedback-text {
            white-space: pre-wrap;
            word-wrap: break-word;
        }
    </style>
</head>
<body>
    <div class="header">
        <h2>📧 User Feedback Received</h2>
    </div>
    <div class="content">
        <div class="field">
            <span class="label">Submitted By:</span>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <span class="label">Subject:</span>
            <div class="value">%s</div>
        </div>
        <div class="field">
            <span class="label">Feedback Content:</span>
            <div class="value feedback-text">%s</div>
        </div>
    </div>
</body>
</html>`, escapeHTML(userName), escapeHTML(subject), escapeHTML(feedbackContent))

	htmlPart.Write([]byte(htmlContent))

	// Close the multipart writer
	err = writer.Close()
	if err != nil {
		return "", fmt.Errorf("failed to close multipart writer: %w", err)
	}

	return buf.String(), nil
}

// escapeHTML escapes special HTML characters to prevent XSS
func escapeHTML(s string) string {
	var result bytes.Buffer
	for _, r := range s {
		switch r {
		case '&':
			result.WriteString("&amp;")
		case '<':
			result.WriteString("&lt;")
		case '>':
			result.WriteString("&gt;")
		case '"':
			result.WriteString("&quot;")
		case '\'':
			result.WriteString("&#39;")
		default:
			result.WriteRune(r)
		}
	}
	return result.String()
}

// encodeBase64 encodes string to base64 for email transfer encoding
func encodeBase64(s string) string {
	return base64.StdEncoding.EncodeToString([]byte(s))
}

func main() {
	// Example usage
	emailBody, err := BuildFeedbackEmail(
		"no-reply@example.com",
		"support@example.com",
		"John Doe",
		"App Crash on Login",
		"Hello,\n\nI encountered a crash when trying to log in to the mobile app. This happens every time I enter my credentials.\n\nSteps to reproduce:\n1. Open the app\n2. Enter username and password\n3. Click login button\n\nPlease fix this issue ASAP.\n\nThanks!",
	)

	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println(emailBody)
}

